const items_out = [];

for (const item of items) {
  const msg = item.json;

  // Extract label names as a flat array
  const labelNames = (msg.labels || []).map(l => l.name);

  // Build clean normalized object
  items_out.push({
    json: {
      message_id:   msg.id,
      thread_id:    msg.threadId,
      subject:      msg.Subject || msg.subject || '(no subject)',
      from:         msg.From || msg.from || '',
      to:           msg.To || msg.to || '',
      snippet:      msg.snippet || '',
      date:         msg.internalDate 
                      ? new Date(parseInt(msg.internalDate)).toISOString()
                      : '',
      labels:       labelNames,
      is_unread:    labelNames.includes('UNREAD'),
      is_inbox:     labelNames.includes('INBOX'),
      account:      'gmail',
      // body will be added in next iteration
      // keeping this field present for schema consistency
      body:         msg.body || msg.snippet || '',
    }
  });
}

return items_out;
